{
  "schema": "brainflow.procedural_policy.v1",
  "name": "cli_arg_length_policy",
  "purpose": "Reduce Windows CLI arg-length risk by preferring file-based payloads over long inline arguments.",
  "rules": [
    {
      "when": "building_cli_commands",
      "prefer": "@file or temp file inputs",
      "avoid": "large inline JSON or long prompt strings"
    },
    {
      "when": "payload_size_gt": 2048,
      "action": "write_payload_to_file_and_pass_path"
    }
  ]
}
